// Normalize incoming email records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    messageId: String(j.messageId ?? j.id ?? '').trim(),
    from: typeof j.from === 'string' ? j.from.trim() : j.from ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Score each email 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.from) score += 20;
  if (j.subject) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});

// Round-robin owner assignment
const owners = ['ava@company.com', 'liam@company.com', 'mia@company.com'];
return $input.all().map((item, i) => ({
  json: { ...item.json, owner: owners[i % owners.length] },
}));

// Compare current metrics with the previous snapshot
const current = $input.first().json;
const prev = $('Load Previous Snapshot').first().json || {};
const drift = {};
for (const k of Object.keys(current)) {
  if (typeof current[k] === 'number' && typeof prev[k] === 'number' && prev[k] !== 0) {
    drift[k] = Math.round(((current[k] - prev[k]) / prev[k]) * 1000) / 10;
  }
}
return [{ json: { ...current, driftPct: drift, hasDrift: Object.values(drift).some(v => Math.abs(v) > 10) } }];
